def read_text(path):
    for enc in ("utf-8", "cp1252", "latin-1"):
        try:
            return Path(path).read_text(encoding=enc)
        except Exception:
            pass
    raise RuntimeError(f"Cannot read {path}")

def write_text(path, text):
    Path(path).write_text(text, encoding="utf-8", newline="\n")

